@app.route('/reset-mfa', methods=['GET', 'POST'])
def reset_mfa():
    email = request.form.get('email')
    user = User.query.filter_by(email=email).first()

    if user:
        token = serializer.dumps({'user_id': user.id})
        reset_link = url_for('reset_mfa_confirm', token=token, _external=True)

        msg = Message('MFA Reset Link', sender='your_mail_username', recipients=[email])
        msg.body = f'Click this link to reset your MFA settings: {reset_link}'
        mail.send(msg)

        return redirect(url_for('mfa_reset_confirmation'))

@app.route('/reset-mfa-confirm/<token>')
def reset_mfa_confirm(token):
    try:
        data = serializer.loads(token)
        user_id = data['user_id']
        user = User.query.get(user_id)

        if user:
            user.mfa_enabled = False
            db.session.commit()

            return redirect(url_for('login'))

    except Exception:
        return 'Invalid token'

